import { useState } from "react";
import styled from "@emotion/styled";
import { Icon } from "@leafygreen-ui/icon";
import { IconButton } from "@leafygreen-ui/icon-button";
import { palette } from "@leafygreen-ui/palette";
import { size, transitionDuration } from "../../constants/tokens";

const { gray } = palette;

export enum AccordionCaretAlign {
  Start = "start",
  Center = "center",
  End = "end",
}

export enum AccordionCaretIcon {
  Caret = "Caret",
  Chevron = "Chevron",
}

interface AccordionProps {
  caretAlign?: AccordionCaretAlign;
  caretIcon?: AccordionCaretIcon;
  children: React.ReactNode;
  className?: string;
  "data-cy"?: string;
  defaultOpen?: boolean;
  disableAnimations?: boolean;
  onToggle?: (s: { isVisible: boolean }) => void;
  open?: boolean;
  subtitle?: React.ReactNode;
  title: React.ReactNode;
  titleTag?: React.FC;
  toggledTitle?: React.ReactNode;
  useIndent?: boolean;
}

const Accordion: React.FC<AccordionProps> = ({
  caretAlign = AccordionCaretAlign.Center,
  caretIcon = AccordionCaretIcon.Chevron,
  children,
  className,
  "data-cy": dataCy,
  defaultOpen = false,
  disableAnimations = true,
  onToggle = () => {},
  open,
  subtitle,
  title,
  titleTag,
  toggledTitle,
  useIndent = true,
}) => {
  const isControlled = open !== undefined;

  const [uncontrolledAccordionOpen, setUncontrolledAccordionOpen] =
    useState(defaultOpen);

  // When controlled, use the open prop. Otherwise, use the uncontrolled state.
  const accordionOpen = isControlled ? open : uncontrolledAccordionOpen;
  const setAccordionOpen = isControlled
    ? () => {}
    : setUncontrolledAccordionOpen;

  const TitleTag = titleTag ?? "span";
  const titleToShow = toggledTitle && accordionOpen ? toggledTitle : title;
  const titleComp = <TitleTag>{titleToShow}</TitleTag>;

  const toggleAccordionHandler = () => {
    onToggle({ isVisible: !accordionOpen });
    setAccordionOpen(!accordionOpen);
  };

  return (
    <div className={className} data-cy={dataCy}>
      <AccordionToggle
        data-cy="accordion-toggle"
        onClick={toggleAccordionHandler}
        role="button"
      >
        <AccordionIcon
          aria-label="Accordion icon"
          open={accordionOpen}
          style={{ alignSelf: caretAlign }}
        >
          <Icon fill={gray.dark1} glyph={`${caretIcon}Right`} />
        </AccordionIcon>
        {titleComp}
      </AccordionToggle>
      {subtitle && <SubtitleContainer>{subtitle}</SubtitleContainer>}
      <AnimatedAccordion
        aria-expanded={accordionOpen}
        data-cy="accordion-collapse-container"
        disableAnimations={disableAnimations}
        hide={!accordionOpen}
      >
        <ContentsContainer useIndent={useIndent}>{children}</ContentsContainer>
      </AnimatedAccordion>
    </div>
  );
};

const AccordionToggle = styled.div`
  display: flex;
  align-items: center;
  gap: 2px;
  :hover {
    cursor: pointer;
  }
`;

const AccordionIcon = styled(IconButton)<{ open: boolean }>`
  flex-shrink: 0;
  transform: ${({ open }) => (open ? "rotate(90deg)" : "unset")};
  transition-property: transform;
  transition-duration: ${transitionDuration.default}ms;
`;

const AnimatedAccordion = styled.div<{
  hide: boolean;
  disableAnimations: boolean;
}>`
  display: grid;
  grid-template-rows: ${({ hide }): string => (hide ? "0fr" : "1fr")};
  ${({ disableAnimations }) =>
    !disableAnimations &&
    `transition: grid-template-rows ${transitionDuration.default}ms ease;`}
`;

const ContentsContainer = styled.div<{ useIndent: boolean }>`
  overflow: hidden;
  ${({ useIndent }) =>
    useIndent &&
    `
      margin-left: 26px;

      /* Handle input focus borders which get cut off due to overflow: hidden */
      padding: 0 ${size.xxs};
    `}
`;

const SubtitleContainer = styled.div`
  margin-left: 30px;
`;

export default Accordion;

export enum TaskStatus {
  Inactive = "inactive",

  // TaskUnstarted is assigned to a display task after cleaning up one of
  // its execution tasks. This indicates that the display task is
  // pending a rerun
  Unstarted = "unstarted",

  // TaskUndispatched indicates either
  //  1. a task is not scheduled to run (when Task.Activated == false)
  //  2. a task is scheduled to run (when Task.Activated == true)
  Undispatched = "undispatched",
  WillRun = "will-run",
  Unscheduled = "unscheduled",

  // TaskStarted indicates a task is currently running
  Started = "started",

  // TaskDispatched indicates that an agent has received the task, but
  // the agent has not yet told Evergreen that it's running the task
  Dispatched = "dispatched",

  // This is a temporary status which is the same as undispatched, but
  // with the additional info that it's waiting for a dependency
  Pending = "pending",

  // The statuses below indicate that a task has finished.
  Succeeded = "success",

  // These statuses indicate that the task failed, and it is likely a problem
  // with the code being tested
  Failed = "failed",
  TestTimedOut = "test-timed-out",
  TaskTimedOut = "task-timed-out",

  // These statuses indicate that the task failed, and it is likely a problem
  // with the systems running the task
  SetupFailed = "setup-failed",
  SystemFailed = "system-failed",
  SystemTimedOut = "system-timed-out",
  SystemUnresponsive = "system-unresponsive",

  // This status means that the task will not run because a dependency was
  // not satisfied
  Blocked = "blocked",
  Aborted = "aborted",

  KnownIssue = "known-issue",
}

// Task status sorted in order of "relevance", with the most likely actionable at the top.
export const SortedTaskStatus = [
  TaskStatus.Failed,
  TaskStatus.TestTimedOut,
  TaskStatus.TaskTimedOut,
  TaskStatus.KnownIssue,
  TaskStatus.SetupFailed,
  TaskStatus.SystemFailed,
  TaskStatus.SystemTimedOut,
  TaskStatus.SystemUnresponsive,
  TaskStatus.Started,
  TaskStatus.Dispatched,
  TaskStatus.Succeeded,
  TaskStatus.Undispatched,
  TaskStatus.WillRun,
  TaskStatus.Aborted,
  TaskStatus.Blocked,
  TaskStatus.Unscheduled,
];

export enum TaskStatusUmbrella {
  Failed = "failed-umbrella",
  SystemFailure = "system-failure-umbrella",
  Running = "running-umbrella",
  Undispatched = "undispatched-umbrella",
  Scheduled = "scheduled-umbrella",
}

export enum TestStatus {
  Fail = "fail",
  Skip = "skip",
  SilentFail = "silentfail",
  Pass = "pass",
}

