      <Popconfirm
        title="Are you sure?"
        confirmText="Yes"
        open={isOpen}
        setOpen={setIsOpen}
        onConfirm={() => {
          setIsOpen(false);
          console.log('Confirmed');
        }}
        onClose={() => setIsOpen(false)}
      >
        <button onClick={() => setIsOpen(true)}>Show Popconfirm</button>
      </Popconfirm>
    );
  },
};

