    20→
    21→interface AccordionProps {
    22→  caretAlign?: AccordionCaretAlign;
    23→  caretIcon?: AccordionCaretIcon;
    24→  children: React.ReactNode;
    25→  className?: string;
    26→  "data-cy"?: string;
    27→  defaultOpen?: boolean;
    28→  disableAnimations?: boolean;
    29→  onToggle?: (s: { isVisible: boolean }) => void;
    30→  open?: boolean;
    31→  subtitle?: React.ReactNode;
    32→  title: React.ReactNode;
    33→  titleTag?: React.FC;
    34→  toggledTitle?: React.ReactNode;
    35→  useIndent?: boolean;
    36→}
    37→
    38→const Accordion: React.FC<AccordionProps> = ({
    39→  caretAlign = AccordionCaretAlign.Center,
    40→  caretIcon = AccordionCaretIcon.Chevron,
    41→  children,
    42→  className,
    43→  "data-cy": dataCy,
